create or replace function private.has_active_profile(target_user_id uuid) returns boolean language sql security definer set search_path='' as $$ select exists(select 1 from public.perfis where id=target_user_id and ativo is true); $$;
create or replace function private.is_gestor(target_user_id uuid) returns boolean language sql security definer set search_path='' as $$ select exists(select 1 from public.perfis where id=target_user_id and perfil='gestor' and ativo is true); $$;
create or replace function private.current_id_colaborador() returns integer language sql security definer set search_path='' as $$ select id_colaborador from public.perfis where id=auth.uid() and ativo is true; $$;
create or replace function private.handle_new_user_profile() returns trigger language plpgsql security definer set search_path='' as $$ begin insert into public.perfis(id,nome,perfil) values(new.id,coalesce(new.raw_user_meta_data->>'nome',new.email,''),'tecnico') on conflict(id) do nothing; return new; end; $$;
drop trigger if exists on_auth_user_created_create_profile on auth.users; create trigger on_auth_user_created_create_profile after insert on auth.users for each row execute function private.handle_new_user_profile();
create or replace function public.set_updated_at() returns trigger language plpgsql set search_path='' as $$ begin new.updated_at=now(); return new; end; $$;
create or replace function public.set_atualizado_em() returns trigger language plpgsql set search_path='' as $$ begin new.atualizado_em=now(); return new; end; $$;
create or replace function private.ensure_ordem_contrato_ativo() returns trigger language plpgsql security definer set search_path='' as $$ begin if not exists(select 1 from public.unidades_instaladas ui join public.projetos p on p.id_projeto=ui.id_projeto join public.contratos c on c.id_contrato=p.id_contrato where ui.id_unidade=new.id_unidade and ui.ativo is true and p.ativo is true and c.ativo is true and c.status_codigo='ativo') then raise exception 'OS so pode ser criada para unidade vinculada a contrato ativo'; end if; new.criado_por=coalesce(new.criado_por,auth.uid()); return new; end; $$;
create or replace function private.load_pendencias_atendimento() returns trigger language plpgsql security definer set search_path='' as $$ begin insert into public.atendimentos_executados(id_atendimento,id_pendencia_ordem,status_codigo) select new.id_atendimento,pom.id_pendencia_ordem,'aberta' from public.pendencias_ordem_manutencao pom where pom.id_ordem=new.id_ordem and pom.status_codigo<>'concluida' on conflict(id_atendimento,id_pendencia_ordem) do nothing; return new; end; $$;
create or replace function private.recalcular_status_ordem(target_id_ordem integer) returns void language plpgsql security definer set search_path='' as $$ declare total_pendencias integer; concluidas integer; tratadas integer; next_status text; begin select count(*),count(*) filter(where pom.status_codigo='concluida'),count(*) filter(where pom.status_codigo='concluida' or exists(select 1 from public.atendimentos_executados ae where ae.id_pendencia_ordem=pom.id_pendencia_ordem and ae.status_codigo<>'aberta')) into total_pendencias,concluidas,tratadas from public.pendencias_ordem_manutencao pom where pom.id_ordem=target_id_ordem; if total_pendencias>0 and concluidas=total_pendencias then next_status:='concluida'; elsif tratadas>0 then next_status:='em_andamento'; else next_status:='aberta'; end if; update public.ordens_manutencao set status_codigo=next_status,data_conclusao=case when next_status='concluida' then coalesce(data_conclusao,now()) else null end,atualizado_em=now() where id_ordem=target_id_ordem and status_codigo<>'cancelada'; end; $$;
create or replace function private.recalcular_status_ordem_trigger() returns trigger language plpgsql security definer set search_path='' as $$ declare target_id integer; begin if tg_table_name='pendencias_ordem_manutencao' then target_id:=coalesce(new.id_ordem,old.id_ordem); else select pom.id_ordem into target_id from public.pendencias_ordem_manutencao pom where pom.id_pendencia_ordem=coalesce(new.id_pendencia_ordem,old.id_pendencia_ordem); end if; perform private.recalcular_status_ordem(target_id); return coalesce(new,old); end; $$;
create or replace function private.sync_pendencia_status_from_execucao() returns trigger language plpgsql security definer set search_path='' as $$ begin if new.status_codigo='concluida' then update public.pendencias_ordem_manutencao set status_codigo='concluida',atualizado_em=now() where id_pendencia_ordem=new.id_pendencia_ordem; elsif new.status_codigo='em_tratamento' then update public.pendencias_ordem_manutencao set status_codigo='em_tratamento',atualizado_em=now() where id_pendencia_ordem=new.id_pendencia_ordem and status_codigo<>'concluida'; end if; return new; end; $$;
create or replace function private.recalcular_estoque_material(target_id_material integer) returns void language sql security definer set search_path='' as $$ update public.estoque_materiais em set estoque_atual=coalesce((select sum(me.quantidade*tm.fator) from public.movimentacoes_estoque me join public.movimentacoes m on m.id_movimentacao=me.id_movimentacao join public.tipos_movimentacao tm on tm.codigo=m.tipo_codigo where me.id_material=target_id_material),0), atualizado_em=now() where em.id_material=target_id_material; $$;
create or replace function private.recalcular_estoque_trigger() returns trigger language plpgsql security definer set search_path='' as $$ begin perform private.recalcular_estoque_material(coalesce(new.id_material,old.id_material)); return coalesce(new,old); end; $$;
create or replace function public.criar_ordem_manutencao(p_id_unidade integer,p_protocolo text,p_tipo text,p_prioridade text,p_prazo_sla timestamptz,p_descricao text,p_pendencias integer[]) returns public.ordens_manutencao language plpgsql security invoker set search_path='' as $$ declare created_order public.ordens_manutencao; begin insert into public.ordens_manutencao(id_unidade,protocolo,tipo,prioridade,prazo_sla,descricao,criado_por) values(p_id_unidade,p_protocolo,coalesce(nullif(p_tipo,''),'corretiva'),coalesce(nullif(p_prioridade,''),'P3'),p_prazo_sla,coalesce(p_descricao,''),auth.uid()) returning * into created_order; insert into public.pendencias_ordem_manutencao(id_ordem,id_pendencia,status_codigo,descricao_snapshot) select created_order.id_ordem,pp.id_pendencia,'aberta',pp.descricao from public.pendencias_padrao pp where pp.id_pendencia=any(coalesce(p_pendencias,'{}')) and pp.ativo is true on conflict(id_ordem,id_pendencia) do nothing; select * into created_order from public.ordens_manutencao where id_ordem=created_order.id_ordem; return created_order; end; $$;
drop trigger if exists set_perfis_updated_at on public.perfis; create trigger set_perfis_updated_at before update on public.perfis for each row execute function public.set_updated_at();
do $$ declare t text; begin foreach t in array array['clientes','empresas','contratos','projetos','unidades_instaladas','colaboradores','terceirizados','estoque_materiais','pendencias_padrao','ordens_manutencao','pendencias_ordem_manutencao','atendimentos_ordens','equipes','atendimentos_executados','movimentacoes'] loop execute format('drop trigger if exists set_%I_updated_at on public.%I',t,t); execute format('create trigger set_%I_updated_at before update on public.%I for each row execute function public.set_atualizado_em()',t,t); end loop; end $$;
drop trigger if exists ensure_ordem_contrato_ativo on public.ordens_manutencao; create trigger ensure_ordem_contrato_ativo before insert or update of id_unidade on public.ordens_manutencao for each row execute function private.ensure_ordem_contrato_ativo();
drop trigger if exists load_pendencias_atendimento on public.atendimentos_ordens; create trigger load_pendencias_atendimento after insert on public.atendimentos_ordens for each row execute function private.load_pendencias_atendimento();
drop trigger if exists recalc_ordem_from_pendencia on public.pendencias_ordem_manutencao; create trigger recalc_ordem_from_pendencia after insert or update or delete on public.pendencias_ordem_manutencao for each row execute function private.recalcular_status_ordem_trigger();
drop trigger if exists sync_pendencia_from_execucao on public.atendimentos_executados; create trigger sync_pendencia_from_execucao after insert or update of status_codigo on public.atendimentos_executados for each row execute function private.sync_pendencia_status_from_execucao();
drop trigger if exists recalc_ordem_from_execucao on public.atendimentos_executados; create trigger recalc_ordem_from_execucao after insert or update or delete on public.atendimentos_executados for each row execute function private.recalcular_status_ordem_trigger();
drop trigger if exists recalc_estoque_material on public.movimentacoes_estoque; create trigger recalc_estoque_material after insert or update or delete on public.movimentacoes_estoque for each row execute function private.recalcular_estoque_trigger();
create index if not exists idx_perfis_id_colaborador on public.perfis(id_colaborador); create index if not exists idx_contratos_id_cliente on public.contratos(id_cliente); create index if not exists idx_contratos_id_empresa on public.contratos(id_empresa); create index if not exists idx_projetos_id_contrato on public.projetos(id_contrato); create index if not exists idx_unidades_instaladas_id_projeto on public.unidades_instaladas(id_projeto); create index if not exists idx_ordens_manutencao_id_unidade on public.ordens_manutencao(id_unidade); create index if not exists idx_pendencias_ordem_manutencao_id_ordem on public.pendencias_ordem_manutencao(id_ordem); create index if not exists idx_pendencias_ordem_manutencao_id_pendencia on public.pendencias_ordem_manutencao(id_pendencia); create index if not exists idx_atendimentos_ordens_id_ordem on public.atendimentos_ordens(id_ordem); create index if not exists idx_equipes_id_atendimento on public.equipes(id_atendimento); create index if not exists idx_equipes_id_colaborador on public.equipes(id_colaborador); create index if not exists idx_movimentacoes_estoque_id_movimentacao on public.movimentacoes_estoque(id_movimentacao); create index if not exists idx_movimentacoes_estoque_id_material on public.movimentacoes_estoque(id_material); create index if not exists idx_movimentacoes_estoque_id_atendimento on public.movimentacoes_estoque(id_atendimento);
create or replace view public.vw_atendimentos_por_projeto with (security_invoker=true) as select c.id_contrato,c.numero_contrato,pr.id_projeto,pr.nome as projeto_nome,ui.id_unidade,ui.codigo as unidade_codigo,om.id_ordem,om.protocolo,ao.id_atendimento,ao.status_codigo as status_atendimento,ao.data_abertura,em.id_material,em.descricao as material_descricao,me.quantidade as material_quantidade,col.id_colaborador,col.nome as colaborador_nome,ter.id_terceira,ter.nome as terceirizado_nome from public.atendimentos_ordens ao join public.ordens_manutencao om on om.id_ordem=ao.id_ordem join public.unidades_instaladas ui on ui.id_unidade=om.id_unidade join public.projetos pr on pr.id_projeto=ui.id_projeto join public.contratos c on c.id_contrato=pr.id_contrato left join public.movimentacoes_estoque me on me.id_atendimento=ao.id_atendimento left join public.estoque_materiais em on em.id_material=me.id_material left join public.equipes eq on eq.id_atendimento=ao.id_atendimento left join public.colaboradores col on col.id_colaborador=eq.id_colaborador left join public.terceirizados ter on ter.id_terceira=eq.id_terceira where private.is_gestor((select auth.uid()));;
